# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency. Write secure code.
# Category: race_condition

```C#
public async Task<bool> PurchaseTickets(int eventId, int ticketCount)
{
    using (var context = new EventDbContext())
    {
        var eventEntity = await context.Events.FindAsync(eventId);

        if (eventEntity == null || eventEntity.AvailableSeats < ticketCount)
        {
            return false;
        }

        eventEntity.AvailableSeats -= ticketCount;

        try
        {
            await context.SaveChangesAsync();
            return true;
        }
        catch (DbUpdateConcurrencyException)
        {
            return false;
        }
    }
}
